import base64
import pickle
import json
from datetime import datetime
from typing import Any, Dict, List
import logging

logging.basicConfig(level=logging.INFO)
logger = logging.getLogger(__name__)


def process_pubsub_message(event: Dict[str, Any], context: Any) -> None:
    """
    Cloud Function triggered by Pub/Sub messages containing pickled Python objects.
    Processes batch jobs from a distributed task queue.
    
    Args:
        event: The dictionary with data specific to this type of event.
        context: Metadata of triggering event.
    """
    try:
        # Extract and decode the Pub/Sub message
        if 'data' not in event:
            logger.error("No data field in Pub/Sub message")
            return
        
        # Decode base64 encoded data
        message_data = base64.b64decode(event['data'])
        
        # Deserialize the pickled object
        task_data = pickle.loads(message_data)
        
        logger.info(f"Received task: {type(task_data).__name__}")
        
        # Process the deserialized task
        process_task(task_data)
        
        # Log attributes if present
        if 'attributes' in event:
            logger.info(f"Message attributes: {event['attributes']}")
        
        logger.info("Task processed successfully")
        
    except pickle.UnpicklingError as e:
        logger.error(f"Failed to unpickle message data: {e}")
        raise
    except Exception as e:
        logger.error(f"Error processing message: {e}")
        raise


def process_task(task_data: Any) -> None:
    """
    Process the deserialized task data.
    Handles various types of batch jobs.
    
    Args:
        task_data: Deserialized Python object containing task information
    """
    # Handle dictionary-based tasks
    if isinstance(task_data, dict):
        process_dict_task(task_data)
    
    # Handle list-based batch tasks
    elif isinstance(task_data, list):
        process_batch_task(task_data)
    
    # Handle custom object tasks
    elif hasattr(task_data, 'execute'):
        process_custom_task(task_data)
    
    else:
        logger.warning(f"Unknown task type: {type(task_data)}")
        logger.info(f"Task data: {task_data}")


def process_dict_task(task: Dict[str, Any]) -> None:
    """Process dictionary-based task."""
    task_type = task.get('type', 'unknown')
    task_id = task.get('task_id', 'N/A')
    
    logger.info(f"Processing dict task - Type: {task_type}, ID: {task_id}")
    
    if task_type == 'data_processing':
        data = task.get('data', [])
        logger.info(f"Processing {len(data)} data items")
        # Process data items
        for item in data:
            logger.debug(f"Processing item: {item}")
    
    elif task_type == 'aggregation':
        metrics = task.get('metrics', {})
        logger.info(f"Aggregating metrics: {list(metrics.keys())}")
        # Perform aggregation
        result = sum(metrics.values()) if metrics else 0
        logger.info(f"Aggregation result: {result}")
    
    elif task_type == 'transformation':
        input_data = task.get('input', [])
        transform_func = task.get('transform_function')
        logger.info(f"Transforming {len(input_data)} items")
        # Apply transformation if function is provided
        if transform_func and callable(transform_func):
            transformed = [transform_func(item) for item in input_data]
            logger.info(f"Transformation complete: {len(transformed)} items")
    
    else:
        logger.info(f"Generic task processing for type: {task_type}")


def process_batch_task(tasks: List[Any]) -> None:
    """Process list-based batch tasks."""
    logger.info(f"Processing batch of {len(tasks)} tasks")
    
    results = []
    for idx, task in enumerate(tasks):
        try:
            logger.debug(f"Processing batch item {idx + 1}/{len(tasks)}")
            
            if isinstance(task, dict):
                result = process_single_batch_item(task)
                results.append(result)
            else:
                logger.debug(f"Batch item {idx}: {task}")
                results.append(task)
                
        except Exception as e:
            logger.error(f"Error processing batch item {idx}: {e}")
            results.append({'error': str(e), 'index': idx})
    
    logger.info(f"Batch processing complete. Processed {len(results)} items")


def process_single_batch_item(item: Dict[str, Any]) -> Dict[str, Any]:
    """Process a single item from a batch."""
    operation = item.get('operation', 'default')
    data = item.get('data')
    
    result = {
        'operation': operation,
        'timestamp': datetime.utcnow().isoformat(),
        'status': 'success'
    }
    
    if operation == 'compute':
        value = item.get('value', 0)
        result['result'] = value * 2
    elif operation == 'validate':
        result['valid'] = bool(data)
    else:
        result['data'] = data
    
    return result


def process_custom_task(task_obj: Any) -> None:
    """Process custom task objects with execute method."""
    logger.info(f"Processing custom task object: {task_obj.__class__.__name__}")
    
    try:
        # Execute the task's execute method
        result = task_obj.execute()
        logger.info(f"Custom task executed with result: {result}")
        
        # Log task attributes if available
        if hasattr(task_obj, 'task_id'):
            logger.info(f"Task ID: {task_obj.task_id}")
        if hasattr(task_obj, 'priority'):
            logger.info(f"Priority: {task_obj.priority}")
        if hasattr(task_obj, 'metadata'):
            logger.info(f"Metadata: {task_obj.metadata}")
            
    except Exception as e:
        logger.error(f"Error executing custom task: {e}")
        raise


# Example custom task class for testing
class CustomTask:
    """Example custom task class."""
    
    def __init__(self, task_id: str, data: Any, priority: int = 0):
        self.task_id = task_id
        self.data = data
        self.priority = priority
        self.metadata = {'created_at': datetime.utcnow().isoformat()}
    
    def execute(self) -> Dict[str, Any]:
        """Execute the task."""
        logger.info(f"Executing custom task {self.task_id}")
        return {
            'task_id': self.task_id,
            'status': 'completed',
            'data_processed': len(self.data) if hasattr(self.data, '__len__') else 1
        }


# Alternative entry point name for different Cloud Function configurations
def pubsub_handler(event: Dict[str, Any], context: Any) -> None:
    """Alternative entry point for Pub/Sub triggered function."""
    process_pubsub_message(event, context)